const data = $input.first().json;
const licitaciones = data.results || [];

if (licitaciones.length === 0) {
  return [{ json: { continuar: false, total: 0 } }];
}

return licitaciones.map(l => ({
  json: {
    continuar: true,
    id: l.id,
    expediente_id: l.expediente_id,
    titulo: l.titulo,
    importe_base: l.importe_base,
    provincia: l.provincia,
    municipio: l.municipio || '',
    localitzacio: l.municipio ? `${l.municipio}/${l.provincia}` : (l.provincia || 'N/D'),
    organismo: l.organismo_nombre,
    fecha_limite: l.fecha_limite_oferta,
    dias_restantes: l.dias_restantes,
    total_licitaciones: licitaciones.length
  }
}));

// One item per iteration — build the Ollama prompt
const l = $input.first().json;

const importe_fmt = l.importe_base
  ? parseFloat(l.importe_base).toLocaleString('es-ES', { minimumFractionDigits: 0 })
  : 'N/D';

const plazo_txt = l.dias_restantes !== null && l.dias_restantes !== undefined
  ? `${l.dias_restantes} días`
  : 'sin fecha';

const prompt = `Analiza la siguiente licitación pública española y genera un resumen ejecutivo de UNA sola frase (máximo 80 palabras) destacando el aspecto más relevante para una empresa constructora.\n\nLicitación:\n- Título: ${l.titulo}\n- Organismo: ${l.organismo || 'Desconocido'}\n- Localización: ${l.localitzacio || 'N/D'}\n- Importe base: ${importe_fmt} EUR\n- Plazo de presentación: ${plazo_txt}\n\nResponde ÚNICAMENTE con el resumen, sin introducción ni explicación adicional.`;

return [{ json: { ...l, prompt, importe_fmt, plazo_txt } }];

// One item per iteration — merge Ollama response with prompt data
const prev = $('✏️ Preparar prompt Ollama').first().json;
const ollamaResp = $input.first().json;

const ollamaFailed = !!ollamaResp.error || !ollamaResp.response;
const resumen_ia = ollamaFailed ? '' : (ollamaResp.response || '').trim();

return [{
  json: {
    ...prev,
    resumen_ia,
    ollama_error: ollamaFailed,
    ok: !ollamaFailed && resumen_ia.length > 0
  }
}];

// Receives ALL accumulated enriched items after the loop finishes
const items = $input.all();
const fecha = new Date().toLocaleDateString('es-ES');
const total = items.length;

function esc(s) {
  return (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const linies = items.slice(0, 5).map(item => {
  const l = item.json;
  const importe_txt = l.importe_fmt ? `${l.importe_fmt} EUR` : 'N/D';
  const resumen = l.ollama_error
    ? '⚠️ Resum IA no disponible'
    : (l.resumen_ia?.substring(0, 120) || '—');
  return `<b>${esc((l.titulo || 'N/D').substring(0, 70))}</b>\n📍 ${esc(l.localitzacio || 'N/D')} | 💶 ${importe_txt} | ⏰ ${l.plazo_txt || 'sin fecha'}\n<i>${esc(resumen)}</i>`;
});

const peu = total > 5 ? `\n\n<i>... i ${total - 5} licitació${total - 5 !== 1 ? 'ns' : ''} més</i>` : '';

const mensaje = `🏗️ <b>CONSTRUTECH-IA — Noves Licitacions</b>\n📅 ${fecha} — <b>${total}</b> nova${total !== 1 ? 's' : ''}\n\n${linies.join('\n\n')}${peu}`;

return [{ json: { mensaje } }];

